double precisionSqrt(int n,int p){
	int s=0;
	int e=n;
	double ans;
	while(s<=e){
		long long int mid=(s+e)/2;
		if(mid*mid==n){
			ans=mid;
		}
		else if(mid*mid<=n){
			ans=mid;
			s=mid+1;
		}
		else{
			e=mid-1;
		}
	}

	float inc=0.1;
	for(int i=1;i<p;i++){
		while(ans*ans<=n){
			ans+=inc;
		}
		ans=ans-inc;
		inc=inc/10;
	}

	return ans;
}
