    public static double squareRoot(int N, double P) {
        double left = 0;
        double right = N;

        // do a binary search within our limits to find our result within a given epsilon(P) or precision factor.
        while(compare(left, right, P) != Difference.EQUAL) {
            double mid = left + (right - left) / 2;
            double midSquared = mid * mid;
            if(compare(midSquared, N, P) == Difference.LARGER) {
                right = mid;
            } else {
                left = mid;
            }
        }

        return left;
    }

    private enum Difference { EQUAL, SMALLER, LARGER }

    private static Difference compare(double a, double b, double P) {
        // check the difference against our allowed room for error P/epsilon
        double diff = Math.abs(a - b);
        if(diff < P) {
            return Difference.EQUAL;
        } else {
            return a > b ? Difference.LARGER : Difference.SMALLER;
        } 
    }
